import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../home/components/Navbar';

interface Task {
  id: string;
  name: string;
  dataType: string;
  status: 'processing' | 'pending_mapping' | 'validating' | 'fixing' | 'stored' | 'error';
  errorCount: number;
  updatedAt: string;
  creator: string;
}

const MOCK_TASKS: Task[] = [
  {
    id: 'T001',
    name: '2024春季小麦育种数据.xlsx',
    dataType: '表型数据',
    status: 'pending_mapping',
    errorCount: 0,
    updatedAt: '2024-03-20 14:30',
    creator: '张三'
  },
  {
    id: 'T002',
    name: '实验室基因测序批次A.csv',
    dataType: '基因型数据',
    status: 'fixing',
    errorCount: 12,
    updatedAt: '2024-03-19 09:15',
    creator: '李四'
  },
  {
    id: 'T003',
    name: '历史气象数据导入.xlsx',
    dataType: '环境数据',
    status: 'stored',
    errorCount: 0,
    updatedAt: '2024-03-18 16:45',
    creator: '王五'
  },
  {
    id: 'T004',
    name: '玉米新品种测试报告.pdf',
    dataType: '非结构化文档',
    status: 'processing',
    errorCount: 0,
    updatedAt: '2024-03-21 10:00',
    creator: '赵六'
  }
];
export default function TaskListPage() {
  const navigate = useNavigate();
  const [filterType, setFilterType] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [searchText, setSearchText] = useState('');

  const getStatusTag = (status: Task['status']) => {
    const styles = {
      processing: 'bg-blue-100 text-blue-800',
      pending_mapping: 'bg-yellow-100 text-yellow-800',
      validating: 'bg-purple-100 text-purple-800',
      fixing: 'bg-red-100 text-red-800',
      stored: 'bg-green-100 text-green-800',
      error: 'bg-gray-100 text-gray-800'
    };
    
    const labels = {
      processing: '解析中',
      pending_mapping: '待映射',
      validating: '规则校验中',
      fixing: '需修正',
      stored: '已存储',
      error: '异常'
    };

    return (
      <span className={`px-2 py-1 rounded-full text-xs font-medium ${styles[status]}`}>
        {labels[status]}
      </span>
    );
  };

  const filteredTasks = MOCK_TASKS.filter(task => {
    if (filterType && task.dataType !== filterType) return false;
    if (filterStatus && task.status !== filterStatus) return false;
    if (searchText && !task.name.includes(searchText) && !task.creator.includes(searchText)) return false;
    return true;
  });

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Navbar />
      
      <main className="flex-grow max-w-7xl w-full mx-auto px-6 py-8 pt-24">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-2xl font-bold text-gray-900">数据处理任务</h1>
          <button
            onClick={() => navigate('/tasks/new')}
            className="px-4 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2 cursor-pointer"
          >
            <i className="ri-add-line"></i>
            新建上传任务
          </button>
        </div>

        {/* 筛选区 */}
        <div className="bg-white p-4 rounded-lg shadow-sm mb-6 flex flex-wrap gap-4 items-end">
          <div className="flex flex-col gap-1">
            <label className="text-sm text-gray-600">数据类型</label>
            <select 
              value={filterType}
              onChange={(e) => setFilterType(e.target.value)}
              className="border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-teal-500 focus:border-teal-500 min-w-[160px]"
            >
              <option value="">全部</option>
              <option value="表型数据">表型数据</option>
              <option value="基因型数据">基因型数据</option>
              <option value="环境数据">环境数据</option>
              <option value="非结构化文档">非结构化文档</option>
            </select>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-sm text-gray-600">任务状态</label>
            <select 
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-teal-500 focus:border-teal-500 min-w-[160px]"
            >
              <option value="">全部</option>
              <option value="processing">解析中</option>
              <option value="pending_mapping">待映射</option>
              <option value="validating">规则校验中</option>
              <option value="fixing">需修正</option>
              <option value="stored">已存储</option>
            </select>
          </div>

          <div className="flex flex-col gap-1 flex-grow max-w-md">
            <label className="text-sm text-gray-600">搜索</label>
            <input 
              type="text" 
              placeholder="任务名称 / 创建人" 
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
              className="border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-teal-500 focus:border-teal-500 w-full"
            />
          </div>
        </div>

        {/* 任务表格 */}
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  任务名称
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  数据类型
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  当前状态
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  错误数
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  创建人
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  更新时间
                </th>
                <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  操作
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredTasks.map((task) => (
                <tr key={task.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <button 
                      onClick={() => navigate(`/tasks/${task.id}`)}
                      className="text-teal-600 hover:text-teal-800 font-medium cursor-pointer"
                    >
                      {task.name}
                    </button>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-md border border-gray-200">
                      {task.dataType}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    {getStatusTag(task.status)}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    {task.errorCount > 0 ? (
                      <span className="text-red-600 font-medium">{task.errorCount}</span>
                    ) : (
                      <span className="text-gray-400">-</span>
                    )}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {task.creator}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {task.updatedAt}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    <button 
                      onClick={() => navigate(`/tasks/${task.id}`)}
                      className="text-teal-600 hover:text-teal-900 cursor-pointer"
                    >
                      进入
                    </button>
                  </td>
                </tr>
              ))}
              {filteredTasks.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-gray-500">
                    没有找到符合条件的任务
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
}